import React, { useEffect, useState } from "react";

const AccountSettings = () => {
    const [user, setUser] = useState(null); // Stocke les informations utilisateur
    const [error, setError] = useState(""); // Message d'erreur s'il y a un problème
    const [email, setEmail] = useState(""); // Email récupéré depuis localStorage
    localStorage.setItem('userEmail', email);  // ✅ Ajout de l'email dans localStorage

    console.log("✅ Email stocké dans localStorage:", email);  // Vérification console

    // Récupérer l'email depuis le localStorage
    useEffect(() => {
        const storedEmail = localStorage.getItem("email");
        console.log("🔍 Email récupéré dans AccountSettings:", storedEmail);

        if (!storedEmail) {
            setError("🚨 Aucun email trouvé. Veuillez vous reconnecter.");
        } else {
            setEmail(storedEmail);
        }
    }, []);

    // Charger les informations utilisateur en fonction de l'email
    useEffect(() => {
        if (!email) return; // Si l'email n'est pas défini, ne rien faire

        const fetchUserByEmail = async () => {
            try {
                const response = await fetch(`http://localhost:5001/user/email?email=${email}`);
                if (!response.ok) {
                    throw new Error("Utilisateur non trouvé."); // Gérer les erreurs HTTP
                }

                const data = await response.json();
                setUser(data); // Stocker les données utilisateur récupérées
            } catch (err) {
                setError("Erreur lors de la récupération des informations.");
                console.error("❌ Erreur :", err);
            }
        };

        fetchUserByEmail();
    }, [email]); // Déclencher cet effet uniquement si `email` change

    return (
        <div style={{ padding: "20px" }}>
            <h2>Paramètres du compte</h2>

            {/* Affichage des erreurs */}
            {error && <p style={{ color: "red" }}>{error}</p>}

            {/* Affichage des informations utilisateur */}
            {user ? (
                <div>
                    <p>
                        <strong>Nom :</strong> {user.name}
                    </p>
                    <p>
                        <strong>Email :</strong> {user.email}
                    </p>
                </div>
            ) : (
                !error && <p>Chargement des informations...</p>
            )}
        </div>
    );
};

export default AccountSettings;
